        import csv
        counts = {}
        with open('network_events.csv', 'r') as f:
            reader = csv.DictReader(f)
            for row in reader:
                ip = row['source_ip']
                counts[ip] = counts.get(ip, 0) + 1
        for ip, count in sorted(counts.items(), key=lambda x: x[1], reverse=True):
            print(f'{ip}: {count}')
